def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0.0
        for k in range(1, 6):
            power = ratio ** k
            sign = (-1) ** (k + 1)
            score += sign * power / k
            if k % 2 == 0 and ratio < 0.3:
                score += power * 0.02
        if ratio == 1:
            priorities[i] = 0
            continue
        if ratio < 0.5:
            score += (0.5 - ratio) ** 3 + 0.05
        elif 0.5 <= ratio < 0.75:
            score *= 1.2
        else:
            score *= np.log1p(capacity)
        neighbor_diff_sum = 0
        count = 0
        for offset in range(1, 6):
            left_idx = i - offset
            right_idx = i + offset
            if left_idx >= 0:
                left_cap = bins[left_idx]
                if left_cap > 0:
                    neighbor_diff_sum += abs(capacity - left_cap) / left_cap
                    count += 1
            if right_idx < n:
                right_cap = bins[right_idx]
                if right_cap > 0:
                    neighbor_diff_sum += abs(capacity - right_cap) / right_cap
                    count += 1
        if count > 0:
            avg_diff = neighbor_diff_sum / count
            score += avg_diff * 0.1 * (1 if i % 2 == 0 else 1.5)
        if item > capacity * 0.8:
            score *= 0.7
        elif item < capacity * 0.2:
            score *= 1.3
        priorities[i] = max(score, 0)
    min_val = np.min(priorities[np.isfinite(priorities)])
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_val * 15
    return priorities
